<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>WastedToken Mint | Collectible Challenge Coins</title>
    <style>
        /* Global Reset and Base Styling */
        :root {
            --color-primary: #A0793D; /* Aged Gold/Bronze tone */
            --color-secondary: #1a1a2e; /* Deep Navy/Black background */
            --color-text: #f0f0f0;
            --color-accent: #ffc800;
            --coin-size: 350px;
        }

        body {
            font-family: 'Arial', sans-serif;
            background-color: var(--color-secondary);
            color: var(--color-text);
            margin: 0;
            padding: 0;
            line-height: 1.6;
            overflow-x: hidden;
        }

        /* Utility Classes */
        .container {
            width: 90%;
            max-width: 1200px;
            margin: 0 auto;
            padding: 40px 0;
        }

        h1, h2 {
            text-align: center;
            color: var(--color-accent);
            letter-spacing: 3px;
            text-transform: uppercase;
            margin-bottom: 10px;
        }

        p.subtitle {
            text-align: center;
            font-size: 1.2em;
            margin-bottom: 40px;
            color: #ccc;
        }

        /* Header/Hero Section */
        header {
            padding: 60px 0 80px 0;
            background: linear-gradient(to bottom, rgba(26, 26, 46, 0.95), var(--color-secondary));
            border-bottom: 1px solid #333;
        }

        #coin-hero {
            display: block;
            margin: 40px auto;
            box-shadow: 0 20px 60px rgba(0, 0, 0, 0.5);
            border-radius: 10px;
        }

        /* About Section */
        #about {
            background-color: #141423;
            padding: 80px 0;
            text-align: center;
        }

        .about-content {
            max-width: 800px;
            margin: 0 auto;
        }

        /* Collection Grid */
        #collection h2 {
            padding-top: 40px;
        }

