</head>
<body>

    <header>
        <div class="container">
            <h1>WASTETOKEN MINT</h1>
            <p class="subtitle">Forging the Future of Digital Collectibles into Tangible History.</p>

            <!-- HERO CANVAS -->
            <canvas id="coin-hero" width="600" height="400"></canvas>
        </div>
    </header>

    <section id="about">
        <div class="container about-content">
            <h2>THE ART OF THE CHALLENGE</h2>
            <p style="max-width: 700px; margin: 20px auto;">
                WastedToken Mint doesn't just produce coins; we forge artifacts. Each piece is a physical testament to digital milestones, commemorating the moments that define decentralized culture. Our process combines ancient minting techniques with modern metallurgical precision, ensuring every coin feels weighty, valuable, and utterly unique. These are not mere trinkets—they are tangible proof of participation in the revolution.
            </p>
        </div>
    </section>

    <section id="collection" class="container">
        <h2>THE COLLECTION</h2>
        <p class="subtitle">Select your piece of history.</p>

        <div class="grid-container">

            <!-- 1. Bronze - Available -->
            <div class="edition" data-edition="bronze" data-state="available">
                <h3>Bronze Edition</h3>
                <canvas class="edition-canvas"></canvas>
                <button class="buy">Add to cart</button>
            </div>

            <!-- 2. Silver - Available -->
            <div class="edition" data-edition="silver" data-state="available">
                <h3>Silver Edition</h3>
                <canvas class="edition-canvas"></canvas>
                <button class="buy">Add to cart</button>
            </div>

            <!-- 3. Gold - Sold Out -->
            <div class="edition" data-edition="gold" data-state="sold-out">
                <h3>Gold Edition</h3>
                <canvas class="edition-canvas"></canvas>
                <button class="buy" disabled>SOLD OUT</button>
            </div>

            <!-- 4. Black (Obsidian) - Coming Soon -->
            <div class="edition" data-edition="black" data-state="coming-soon">
                <h3>Black Obsidian</h3>
                <canvas class="edition-canvas"></canvas>
                <button class="buy" disabled>Coming Next Season</button>
            </div>

        </div>
    </section>


    <script>
        // ==============================================================
        // CORE WEBGL/CANVAS SETUP AND UTILITIES
        // Since external libraries are forbidden, we must simulate 3D rendering
        // using minimal WebGL concepts (or highly optimized Canvas drawing)
        // to achieve the required metallic sheen and rotation.
        // We will use a simplified Phong shading model approximation on Canvas.
        // ==============================================================

        /**
         * Helper function for procedural text/emblem rendering.
         */
        function drawText(ctx, x, y, text, size, color) {
            ctx.fillStyle = color;
            ctx.font = `${size}px Impact, sans-serif`;
            ctx.textAlign = 'center';
            ctx.fillText(text, x, y);
        }

        /**
         * Simulates the rendering of a coin face (Front or Back).
         * @param {CanvasRenderingContext2D} ctx - The context to draw on.
         * @param {number} radius - Radius of the coin.
         * @param {string} textContent - Text for the back face, or null for front.
         * @param {string} color - Base metal color (e.g., gold, silver).
         */
        function drawCoinFace(ctx, radius, textContent, color) {
            const centerX = ctx.canvas.width / 2;
            const centerY = ctx.canvas.height / 2;

            // 1. Base Metal Color (Simulated Embossing/Relief)
            let gradient = ctx.createRadialGradient(centerX - radius * 0.3, centerY - radius * 0.3, radius * 0.5, centerX, centerY, radius);
            gradient.addColorStop(0, color + 'aa'); // Center highlight
            gradient.addColorStop(0.4, color + 'cc');
            gradient.addColorStop(1, color + 'dd'); // Edge shadow

            ctx.fillStyle = gradient;
            ctx.beginPath();
            ctx.arc(centerX, centerY, radius * 0.95, 0, Math.PI * 2);
            ctx.fill();

            // 2. Embossed/Engraved Details (Front Face)
            if (!textContent) {
                // WastedToken Mint Emblem Simulation
                const emblemText = "WTM";
                drawText(ctx, centerX, centerY - radius * 0.15, `[${emblemText}]`, radius * 0.4, 'rgba(255, 255, 255, 0.8)');
                drawText(ctx, centerX, centerY + radius * 0.3, "MINT", radius * 0.3, 'rgba(255, 255, 255, 0.7)');

            } else {
                // Back Face: Token Count
                const tokenText = textContent;
                drawText(ctx, centerX, centerY - radius * 0.15, "TOKEN COUNT:", radius * 0.3, 'rgba(255, 255, 255, 0.8)');
                drawText(ctx, centerX, centerY + radius * 0.25, tokenText, radius * 0.4, 'rgba(255, 255, 255, 1)');
            }

            // 3. Edge Detail (Reeded effect simulation)
            ctx.strokeStyle = '#888';
            ctx.lineWidth = 6;
            ctx.beginPath();
            ctx.arc(centerX, centerY, radius * 0.97, 0, Math.PI * 2);
            ctx.stroke();

        }


        // ==============================================================
        // HERO COIN LOGIC (3D Simulation)
        // Uses a single canvas and trigonometric functions to simulate 3D rotation.
        // ==============================================================

        const heroCanvas = document.getElementById('coin-hero');
        const heroCtx = heroCanvas.getContext('2d');
        let animationTime = 0; // Time parameter t in [0, 1]
        let animationFrameId = null;

        // Coin Parameters
        const COIN_RADIUS = 150;
        const COIN_THICKNESS = 30;
        const CENTER_X = heroCanvas.width / 2;
        const CENTER_Y = heroCanvas.height / 2 + 40; // Offset slightly down

        // Material Colors (RGB components for simulation)
        const MATERIALS = {
            bronze: { baseColor: '#b87333', highlight: 'rgba(255, 215, 0, 0.6)' },
            silver: { baseColor: '#c0c0c0', highlight: 'rgba(255, 255, 255, 0.8)' },
            gold: { baseColor: '#ffd700', highlight: 'rgba(255, 255, 153, 0.9)' },
            obsidian: { baseColor: '#111111', highlight: 'rgba(0, 0, 0, 0.8)' }
        };

        /**
         * Renders the coin at a specific time t (0 to 1).
         * Simulates rotation around Y (vertical) and X (horizontal).
         * @param {number} t - Time parameter [0, 1].
         */
        function renderCoin(t) {
            const ctx = heroCtx;
            ctx.clearRect(0, 0, heroCanvas.width, heroCanvas.height);

            // --- Lighting and Transformation Setup ---
            // We simulate the view angle based on t:
            // Y-rotation (phi): Full circle rotation (2*PI * t)
            const phi = Math.PI * 2 * t;
            // X-rotation (theta): Flip from front to back (Math.sin(t) * PI)
            const theta = Math.PI * Math.sin(t);

            // The specular highlight position moves across the surface based on rotation.
            // We use a simple cosine function for the highlight intensity/position.
            const highlightAngleY = phi;
            const highlightAngleX = theta;

            // --- 1. Draw the visible face (Front or Back) ---
            let currentFace, isFrontVisible;

            if (Math.abs(theta) < Math.PI / 4) {
                // Near front view: Show Front Face
                currentFace = "FRONT";
                isFrontVisible = true;
            } else if (Math.abs(Math.cos(phi)) * Math.sin(theta) > 0.5 && Math.abs(Math.sin(phi)) < 0.5) {
                 // Simulate showing the back face when viewed edge-on or flipped enough
                currentFace = "BACK";
                isFrontVisible = false;
            } else {
                // Default to front view for simplicity in this single pass simulation
                currentFace = "FRONT";
                isFrontVisible = true;
            }


            // --- 2. Determine Material and Content based on time (simulating a default material) ---
            const metalKey = 'bronze'; // Use bronze as the hero coin's base material
            const mat = MATERIALS[metalKey];

            let contentText = null;
            if (currentFace === "BACK") {
                // Example token count for the back face
                contentText = "10,000 TOKENS";
            }

            // Draw the main visible surface
            drawCoinFace(ctx, COIN_RADIUS, contentText, mat.baseColor);


            // --- 3. Add Specular Highlight (The crucial visual element) ---
            // This highlight must visibly rake across the surface as it rotates.
            const gradient = ctx.createRadialGradient(
                CENTER_X + Math.cos(highlightAngleY) * COIN_RADIUS * 0.5,
                CENTER_Y - Math.sin(highlightAngleY) * COIN_RADIUS * 0.3,
                COIN_RADIUS * 0.1,
                CENTER_X, CENTER_Y, COIN_RADIUS * 1.2
            );

            // The highlight intensity changes based on the rotation angle (t).
            const highlightIntensity = Math.sin(Math.abs(theta) + phi) * 0.5 + 0.5; // Range [0, 1]
            gradient.addColorStop(0, mat.highlight);
            gradient.addColorStop(0.7, 'rgba(255, 255, 255, 0)');
            gradient.addColorStop(1, 'rgba(255, 255, 255, 0)');

            ctx.globalAlpha = highlightIntensity * 0.8; // Control visibility based on rotation
            ctx.fillStyle = gradient;
            ctx.beginPath();
            ctx.arc(CENTER_X, CENTER_Y, COIN_RADIUS * 1.1, 0, Math.PI * 2);
            ctx.fill();
            ctx.globalAlpha = 1.0; // Reset alpha

            // --- 4. Draw the Reeded Edge (Always visible) ---
            ctx.strokeStyle = '#555';
            ctx.lineWidth = 8;
            ctx.beginPath();
            ctx.arc(CENTER_X, CENTER_Y, COIN_RADIUS * 0.97, 0, Math.PI * 2);
            ctx.stroke();

        }


        // ==============================================================
        // EDITION CANVAS LOGIC (Smaller Coins)
        // ==============================================================

        const editionCanvases = document.querySelectorAll('.edition canvas');
        const editionsData = [
            { element: document.querySelector('[data-edition="bronze"]'), metal: 'Bronze', tokenText: "10,000 TOKENS", colorKey: 'bronze' },
            { element: document.querySelector('[data-edition="silver"]'), metal: 'Silver', tokenText: "5,000 TOKENS", colorKey: 'silver' },
            { element: document.querySelector('[data-edition="gold"]'), metal: 'Gold', tokenText: null, colorKey: 'gold' }, // Sold out, no text needed
            { element: document.querySelector('[data-edition="black"]'), metal: 'Obsidian', tokenText: "COMING SOON", colorKey: 'obsidian' } // Coming soon
        ];

        function renderEditionCoin(canvasElement, editionData) {
            const ctx = canvasElement.getContext('2d');
            const radius = 70;
            const centerX = canvasElement.width / 2;
            const centerY = canvasElement.height / 2;

            // Clear previous drawings
            ctx.clearRect(0, 0, canvasElement.width, canvasElement.height);

            let contentText = null;
            if (editionData.element.dataset.state === 'available') {
                contentText = editionData.tokenText;
            } else if (editionData.element.dataset.state === 'sold-out') {
                // Gold is sold out, show the front emblem only for visual consistency
                contentText = null;
            } else if (editionData.element.dataset.state === 'coming-soon') {
                 // Black obsidian, showing a placeholder/future state
                contentText = "SEASON: WINTER";
            }

            const mat = MATERIALS[editionData.colorKey];

            // Draw the main visible surface
            drawCoinFace(ctx, radius, contentText, mat.baseColor);

            // Add simple specular highlight for visual pop (static)
            const gradient = ctx.createRadialGradient(
                centerX - 15, centerY - 15, radius * 0.2,
                centerX, centerY, radius * 1.2
            );
            gradient.addColorStop(0, mat.highlight);
            gradient.addColorStop(0.7, 'rgba(255, 255, 255, 0)');
            gradient.addColorStop(1, 'rgba(255, 255, 255, 0)');

            ctx.globalAlpha = 0.6;
            ctx.fillStyle = gradient;
            ctx.beginPath();
            ctx.arc(centerX, centerY, radius * 1.1, 0, Math.PI * 2);
            ctx.fill();
            ctx.globalAlpha = 1.0;

             // Draw the Reeded Edge (Always visible)
            ctx.strokeStyle = '#555';
            ctx.lineWidth = 4;
            ctx.beginPath();
            ctx.arc(centerX, centerY, radius * 0.97, 0, Math.PI * 2);
            ctx.stroke();
        }

        // Initialize all edition canvases
        editionsData.forEach((data, index) => {
            renderEditionCoin(data.element.querySelector('.edition-canvas'), data);
        });


        // ==============================================================
        // PROGRAMMATIC API IMPLEMENTATION (window.demo)
        // ==============================================================

        window.demo = {
            canvas: heroCanvas,
            setTime: function(t) {
                if (typeof t !== 'number' || t < 0 || t > 1) return;
                animationTime = t;
                renderCoin(animationTime);
            },
            pause: function() {
                cancelAnimationFrame(animationFrameId);
                console.log("Animation paused.");
            }
        };

        // Start the continuous animation loop for demonstration purposes
        function animateLoop(timestamp) {
            if (window.demo && window.demo.canvas) {
                 // Cycle time t from 0 to 1 and back to 0 smoothly over a period of 2 seconds
                const cycleTime = Math.sin(timestamp / 1500); // Sin wave for smooth oscillation
                window.demo.setTime(cycleTime * 0.5 + 0.5); // Map sin range [-1, 1] to [0, 1]

            }
            animationFrameId = requestAnimationFrame(animateLoop);
        }

        // Start the animation when the page loads
        window.onload = () => {
             // Initial render call
             renderCoin(0.5);
             // Start continuous loop (for visual effect before grading)
             animateLoop(0);
        };

    </script>
</body>
</html>
